class Solution:
    def canThreePartsEqualSum(self, arr):
        total = sum(arr)
        if total % 3 != 0:
            return False
        target = total // 3
        n = len(arr)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + arr[i]
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                if prefix[i] == target and prefix[j] - prefix[i] == target:
                    return True
        return False

