class Solution:
    def canThreePartsEqualSum(self, arr):
        total = sum(arr)
        if total % 3 != 0:
            return False
        target = total // 3
        count = 0
        cur = 0
        for i, v in enumerate(arr):
            cur += v
            if cur == target:
                count += 1
                cur = 0
                if count == 2 and i < len(arr) - 1:
                    return True
        return False

