var canThreePartsEqualSum = function(arr) {
    const total = arr.reduce((a, b) => a + b, 0);
    if (total % 3 !== 0) return false;
    const target = total / 3;
    let count = 0, cur = 0;
    for (let i = 0; i < arr.length; i++) {
        cur += arr[i];
        if (cur === target) {
            count += 1;
            cur = 0;
            if (count === 2 && i < arr.length - 1) return true;
        }
    }
    return false;
};
